import sys
import warnings
from typing import Tuple, List
import category_encoders as ce
from lifelines import CoxPHFitter
import matplotlib.pyplot as plt
import numpy as np
import pandas as pd
import seaborn as sns
from sklearn.model_selection import train_test_split

from pipeline import cli_formatter as cf


# Configure standard terminal encoding and filter warnings
sys.stdout.reconfigure(encoding='utf-8')
warnings.filterwarnings("ignore", category=FutureWarning)
EMBEDDED_CSV_B64 = ""


def load_dataset(file_path: str = None) -> pd.DataFrame:
    """
    Loads the employee attrition dataset. Defaults to the embedded dataset if no path is provided.
    
    Args:
        file_path: Optional path to a CSV file.
        
    Returns:
        A cleaned pandas DataFrame.
    """
    import base64
    import gzip
    import io

    if file_path is None:
        try:
            csv_bytes = gzip.decompress(base64.b64decode(EMBEDDED_CSV_B64))
            data = pd.read_csv(io.BytesIO(csv_bytes), on_bad_lines='skip')
        except Exception as e:
            print(f"Error loading embedded dataset: {e}", file=sys.stderr)
            sys.exit(1)
    else:
        try:
            data = pd.read_csv(file_path, on_bad_lines='skip')
        except FileNotFoundError:
            print(f"Error: Dataset file not found at {file_path}", file=sys.stderr)
            sys.exit(1)
            
    # Remove repeated header rows that can occur during bad lines parsing
    data = data[data['Age'] != 'Age'].copy()
    
    # Drop columns with zero variance or irrelevant unique identifiers
    irrelevant_columns = ['EmployeeCount', 'StandardHours', 'Over18', 'EmployeeNumber']
    data = data.drop(columns=irrelevant_columns, errors='ignore')
    
    # Map target column to boolean format expected by lifelines
    data['Attrition'] = data['Attrition'].map({'Yes': True, 'No': False})
    
    return data


def preprocess_data(data: pd.DataFrame) -> pd.DataFrame:
    # Map ordinal categorical columns to logical scales
    ordinal_mappings = {
        'BusinessTravel': {'Non-Travel': 1, 'Travel_Rarely': 2, 'Travel_Frequently': 3},
        'Education': {'Below College': 1, 'College': 2, 'Bachelor': 3, 'Master': 4, 'Doctor': 5},
        'EnvironmentSatisfaction': {'Low': 1, 'Medium': 2, 'High': 3, 'Very High': 4},
        'JobInvolvement': {'Low': 1, 'Medium': 2, 'High': 3, 'Very High': 4},
        'JobLevel': {'Entry Level': 1, 'Junior Level': 2, 'Mid Level': 3, 'Senior Level': 4, 'Executive Level': 5},
        'JobSatisfaction': {'Low': 1, 'Medium': 2, 'High': 3, 'Very High': 4},
        'PerformanceRating': {'Good': 1, 'Excellent': 2, 'Outstanding': 3},
        'RelationshipSatisfaction': {'Low': 1, 'Medium': 2, 'High': 3, 'Very High': 4},
        'WorkLifeBalance': {'Bad': 1, 'Low': 2, 'Good': 3, 'Better': 4, 'Best': 5}
    }
    for col, mapping in ordinal_mappings.items():
        if col in data.columns:
            data[col] = data[col].replace(mapping)
            
    # List of columns to skip from numeric casting to prevent corrupting text categories
    skip_numeric_cols = [
        'Attrition', 'BusinessTravel', 'Department', 'EducationField',
        'Gender', 'JobRole', 'MaritalStatus', 'OverTime'
    ]
    for col in data.columns:
        if col not in skip_numeric_cols:
            data[col] = pd.to_numeric(data[col], errors='coerce')
            
    # Adjust 0 years of experience for attrited employees to a minimal value to prevent 
    # math limits/failures in survival hazard calculation
    zero_years_attrition = (data['YearsAtCompany'] == 0) & (data['Attrition'] == True)
    data.loc[zero_years_attrition, 'YearsAtCompany'] = 0.01
    return data.dropna()


def split_and_encode_data(
    data: pd.DataFrame, 
    test_size: float = 0.2, 
    random_state: int = 42
) -> Tuple[pd.DataFrame, pd.DataFrame]:
    train_data, test_data = train_test_split(data, test_size=test_size, random_state=random_state)
    
    # One-hot encode low-cardinality categorical variables
    one_hot_cols = ['Gender', 'MaritalStatus', 'OverTime', 'Department']
    train_data = pd.get_dummies(train_data, columns=one_hot_cols, drop_first=True)
    test_data = pd.get_dummies(test_data, columns=one_hot_cols, drop_first=True)
    
    # Align training and testing features to prevent column mismatch
    train_data, test_data = train_data.align(test_data, join='left', axis=1)
    test_data = test_data.fillna(0)
    
    # Apply Leave-One-Out target encoding on high-cardinality nominal columns
    high_cardinality_cols = ['JobRole', 'EducationField']
    target_encoder = ce.LeaveOneOutEncoder(cols=high_cardinality_cols)
    train_data = target_encoder.fit_transform(train_data, train_data['Attrition'].astype(int))
    test_data = target_encoder.transform(test_data)
    return train_data.dropna(), test_data.dropna()


def train_survival_model(train_data: pd.DataFrame) -> CoxPHFitter:
    """
    Fits a Cox Proportional Hazards regression model to the training data.
    """
    print("Training the survival model...")
    cph = CoxPHFitter(penalizer=0.01)
    cph.fit(train_data, duration_col='YearsAtCompany', event_col='Attrition')
    print("Model trained!\n")
    return cph


def plot_analysis_results(
    train_data: pd.DataFrame, 
    test_data: pd.DataFrame, 
    cph: CoxPHFitter
) -> None:
    """
    Plots the Age Distribution and survival cohorts comparison in a single window with interactive page toggling.
    Uses native toolbar back/forward buttons, keyboard arrow keys, and on-figure buttons to switch views.
    """
    from matplotlib.widgets import Button
    
    print("Generating visual analysis charts...")
    fig = plt.figure(figsize=(11, 6.5))
    
    # --- View 1: Data Split Fair Check (Age Distribution) ---
    ax1 = fig.add_subplot(111)
    sns.histplot(train_data['Age'], color='#4C72B0', label='Training Set', kde=True, ax=ax1, stat='density', bins=15)
    sns.histplot(test_data['Age'], color='#DD8452', label='Test Set', kde=True, ax=ax1, stat='density', bins=15)
    ax1.set_title("Age Distribution: Train vs Test Splits", fontsize=14, fontweight='bold')
    ax1.set_xlabel("Employee Age")
    ax1.set_ylabel("Density")
    ax1.legend()
    
    # --- View 2: Cohort Survival Curves ---
    # Predict expected median survival time
    median_survival = cph.predict_median(test_data)
    cutoff = median_survival.median()
    
    # Segment test cohorts based on median survival threshold
    high_risk_employees = test_data[median_survival <= cutoff]
    low_risk_employees = test_data[median_survival > cutoff]
    
    # Generate time grid for predictions
    time_points = np.linspace(0, test_data['YearsAtCompany'].max(), 200)
    
    high_risk_curves = cph.predict_survival_function(high_risk_employees, times=time_points)
    low_risk_curves = cph.predict_survival_function(low_risk_employees, times=time_points)
    
    # Average individual survival probabilities to get aggregate group curves
    high_risk_avg = high_risk_curves.mean(axis=1)
    low_risk_avg = low_risk_curves.mean(axis=1)
    
    ax2 = fig.add_subplot(111)
    # Plot average curves
    ax2.plot(
        high_risk_avg.index, 
        high_risk_avg.values * 100,
        color='#E74C3C', 
        linewidth=2.5,
        label=f'High-Risk (n={len(high_risk_employees)})'
    )
    ax2.plot(
        low_risk_avg.index, 
        low_risk_avg.values * 100,
        color='#2ECC71', 
        linewidth=2.5,
        label=f'Low-Risk (n={len(low_risk_employees)})'
    )
    
    # Shading the risk gap
    ax2.fill_between(
        high_risk_avg.index,
        high_risk_avg.values * 100,
        low_risk_avg.values * 100,
        alpha=0.15, 
        color='#E74C3C', 
        label='Risk Gap'
    )
    
    # Critical Reference Annotations
    ax2.axvline(x=0.5, color='#3498DB', linestyle='--', linewidth=1.5)
    ax2.text(0.55, 50, '6-Month\nMark', fontsize=10, color='#3498DB', fontweight='bold')
    ax2.axhline(y=50, color='gray', linestyle=':', linewidth=1, alpha=0.5)
    
    ax2.set_title("Survival Curves: High-Risk vs Low-Risk Employees", fontsize=14, fontweight='bold')
    ax2.set_xlabel("Years at Company")
    ax2.set_ylabel("Chance of Still Being Employed (%)")
    ax2.set_ylim(0, 105)
    ax2.legend(loc='lower left', fontsize=11)
    
    # Make room at the bottom for the control buttons
    fig.subplots_adjust(bottom=0.18)
    
    # Control logic to switch views
    current_view = 0
    
    def show_view(view_index: int) -> None:
        nonlocal current_view
        current_view = view_index
        if current_view == 0:
            ax1.set_visible(True)
            ax2.set_visible(False)
            fig.suptitle("Viewing Plot: 1 of 2 (Age Split Fairness)", fontsize=11, fontweight='bold', color='gray')
        else:
            ax1.set_visible(False)
            ax2.set_visible(True)
            fig.suptitle("Viewing Plot: 2 of 2 (Cohort Survival Curves)", fontsize=11, fontweight='bold', color='gray')
        fig.canvas.draw_idle()
        
    # Keyboard listener
    def on_key(event) -> None:
        if event.key == 'left':
            show_view(0)
            update_toolbar_button_states()
        elif event.key == 'right':
            show_view(1)
            update_toolbar_button_states()
            
    fig.canvas.mpl_connect('key_press_event', on_key)
    
    # Add on-figure GUI buttons
    ax_prev = fig.add_axes([0.72, 0.03, 0.1, 0.05])
    ax_next = fig.add_axes([0.84, 0.03, 0.1, 0.05])
    
    btn_prev = Button(ax_prev, 'Previous', color='#BDC3C7', hovercolor='#95A5A6')
    btn_next = Button(ax_next, 'Next', color='#3498DB', hovercolor='#2980B9')
    
    def click_prev(event=None) -> None:
        show_view(0)
        update_toolbar_button_states()
        
    def click_next(event=None) -> None:
        show_view(1)
        update_toolbar_button_states()
        
    btn_prev.on_clicked(click_prev)
    btn_next.on_clicked(click_next)
    
    # Configure native toolbar back and forward command bindings (for TkAgg)
    toolbar = fig.canvas.manager.toolbar
    
    def update_toolbar_button_states() -> None:
        if toolbar is not None:
            try:
                toolbar._buttons['Back'].config(state='normal')
                toolbar._buttons['Forward'].config(state='normal')
            except Exception:
                pass
                
    if toolbar is not None:
        try:
            toolbar._buttons['Back'].config(command=click_prev)
            toolbar._buttons['Forward'].config(command=click_next)
            toolbar.set_history_buttons = update_toolbar_button_states
        except Exception:
            pass
            
    # Initialize the default view
    show_view(0)
    update_toolbar_button_states()
    
    plt.show()


def generate_executive_report(cph: CoxPHFitter, test_data: pd.DataFrame) -> None:
    # Extract coefficients and p-values
    report = cph.summary[['exp(coef)', 'p']].copy()
    report.columns = ['Multiplier', 'P_Value']
    
    # Calculate percentage change in risk per unit change in features
    report['Risk_Change_%'] = ((report['Multiplier'] - 1) * 100).round(1)
    report['Direction'] = np.where(report['Risk_Change_%'] > 0, 'Increases Risk', 'Decreases Risk')
    report['Significant'] = np.where(report['P_Value'] < 0.05, 'Yes', 'No')
    report = report.sort_values('Risk_Change_%', ascending=False)
    report['Multiplier'] = report['Multiplier'].round(2)
    report['P_Value'] = report['P_Value'].round(3)
    
    # Initialize terminal colors
    cf.init_terminal()

    # --- Section 1: The Hidden Killers ---
    killers = report[(report['Significant'] == 'Yes') & (report['Direction'] == 'Increases Risk')]
    killers_lines = [
        "These factors are statistically proven to drive attrition",
        "and push employees out the door:",
        "---"
    ]
    if killers.empty:
        killers_lines.append("  None found.")
    else:
        for name, row in killers.iterrows():
            clean_name = name.replace('_', ' ')
            if 'OverTime' in name and 'Yes' in name:
                clean_name = 'Working Overtime'
            elif 'MaritalStatus' in name:
                clean_name = clean_name.replace('MaritalStatus', 'Marital Status:')
            elif 'Department' in name:
                clean_name = clean_name.replace('Department', 'Department:')
            else:
                clean_name = clean_name.title()
            
            val_str = cf.style(f"+{row['Risk_Change_%']}%", cf.RED, cf.BOLD)
            killers_lines.append(f"  {cf.ERR_ICON}  {clean_name:<26} -> Increases risk by {val_str} per unit")

    killers_title = cf.style("THE HIDDEN RISK KILLERS", cf.RED, cf.BOLD)
    print("\n" + cf.make_panel(killers_title, killers_lines, style_color=cf.RED, width=82))

    # --- Section 2: The Retention Shields ---
    shields = report[(report['Significant'] == 'Yes') & (report['Direction'] == 'Decreases Risk')]
    shields_lines = [
        "These factors are statistically proven to protect the workforce",
        "and keep employees from leaving:",
        "---"
    ]
    if shields.empty:
        shields_lines.append("  None found.")
    else:
        for name, row in shields.iterrows():
            clean_name = name.replace('_', ' ').title()
            impact = abs(row['Risk_Change_%'])
            val_str = cf.style(f"-{impact}%", cf.GREEN, cf.BOLD)
            shields_lines.append(f"  {cf.OK_ICON}  {clean_name:<26} -> Reduces risk by {val_str} per unit")

    shields_title = cf.style("THE RETENTION SHIELDS", cf.GREEN, cf.BOLD)
    print("\n" + cf.make_panel(shields_title, shields_lines, style_color=cf.GREEN, width=82))

    # --- Section 3: The False Alarms ---
    noise = report[report['Significant'] == 'No']
    noise_lines = [
        "These factors might seem risky but are statistically insignificant.",
        "Do not spend corporate budget trying to optimize these variables:",
        "---"
    ]
    if noise.empty:
        noise_lines.append("  None found.")
    else:
        count = 0
        for name, _ in noise.iterrows():
            clean_name = name.replace('_', ' ').title()
            noise_lines.append(f"  {cf.WARN_ICON}  {clean_name}")
            count += 1
            if count >= 5:
                noise_lines.append(f"     ... and {len(noise) - 5} more factors")
                break

    noise_title = cf.style("THE FALSE ALARMS (NOISE)", cf.YELLOW, cf.BOLD)
    print("\n" + cf.make_panel(noise_title, noise_lines, style_color=cf.YELLOW, width=82))

    # --- Model Accuracy ---
    accuracy = cph.concordance_index_
    accuracy_lines = [
        f"  Concordance Index (C-Index): {cf.style(f'{accuracy * 100:.1f}%', cf.GREEN, cf.BOLD)}",
        "---",
        f"  {cf.INFO_ICON}  Interpretation:",
        f"     If we pick two random employees (one who quit, one who stayed),",
        f"     the model correctly identifies who is at higher risk about",
        f"     {cf.style(f'{round(accuracy * 100)} out of 100', cf.CYAN, cf.BOLD)} times.",
        "     (Scores above 70% represent high enterprise reliability)"
    ]
    accuracy_title = cf.style("COX MODEL TRAIN ACCURACY & FIT", cf.GREEN, cf.BOLD)
    print("\n" + cf.make_panel(accuracy_title, accuracy_lines, style_color=cf.GREEN, width=82))

    # --- Testing on Hidden Data ---
    test_accuracy = cph.score(test_data, scoring_method='concordance_index')
    test_lines = [
        f"  Unseen Test Set C-Index: {cf.style(f'{test_accuracy * 100:.1f}%', cf.BLUE, cf.BOLD)}",
        "---",
        f"  {cf.OK_ICON}  Validation Summary:",
        f"     The model correctly ranks attrition risk {cf.style(f'{round(test_accuracy * 100)}%', cf.BLUE, cf.BOLD)} of the time",
        "     on brand new employees that it has NEVER seen before.",
        "     This confirms strong generalization and predictive stability."
    ]
    test_title = cf.style("OUT-OF-SAMPLE TEST SET VALIDATION", cf.BLUE, cf.BOLD)
    print("\n" + cf.make_panel(test_title, test_lines, style_color=cf.BLUE, width=82))

    # --- Biggest Takeaway ---
    income_words = ['income', 'salary', 'rate', 'daily', 'monthly', 'hourly']
    income_columns = [
        col for col in report.index 
        if any(word in col.lower() for word in income_words)
    ]
    
    takeaway_lines = []
    if income_columns:
        any_significant = any(report.loc[col, 'Significant'] == 'Yes' for col in income_columns)
        if any_significant:
            takeaway_lines.append(f"  {cf.style('[CRITICAL TAKEAWAY: COMPENSATION]', cf.RED, cf.BOLD)}")
            takeaway_lines.append("  Pay actually matters here. Some salary-related factors are")
            takeaway_lines.append("  statistically significant. Review pay scales for high-turnover roles.")
        else:
            takeaway_lines.append(f"  {cf.style('[RETENTION INSIGHT: COMPENSATION IS NOT KEY]', cf.MAGENTA, cf.BOLD)}")
            takeaway_lines.append("  Money is NOT the main problem!")
            takeaway_lines.append("  Salary, hourly rate, and income are not statistically significant.")
            takeaway_lines.append("  The real problems are non-monetary: Overtime, Job Role, and Manager Quality.")
    else:
        takeaway_lines.append(f"  {cf.style('[RETENTION INSIGHT: CULTURAL FACTORS]', cf.MAGENTA, cf.BOLD)}")
        takeaway_lines.append("  Look at the Hidden Risk Killers panel above to address the root")
        takeaway_lines.append("  drivers of attrition (e.g., overtime, role assignments, or managers).")

    takeaway_title = cf.style("EXECUTIVE STRATEGY TAKEAWAY", cf.MAGENTA, cf.BOLD)
    print("\n" + cf.make_panel(takeaway_title, takeaway_lines, style_color=cf.MAGENTA, width=82) + "\n")

    # Generate HTML Dashboard Report
    from pipeline.html_reporter import generate_cox_html_report
    generate_cox_html_report(
        report_df=report,
        train_cindex=accuracy,
        test_cindex=test_accuracy,
        output_path="report_cox.html"
    )



def main() -> None:
    dataset_path = None  # None loads the embedded dataset
    
    # Load and clean dataset
    raw_data = load_dataset(dataset_path)

    # Preprocess ordinal values and cast appropriate types
    preprocessed_data = preprocess_data(raw_data)
    print(f"Dataset cleaned. Total employees: {len(preprocessed_data)}")
    
    # Split and encode categorical variables
    train_data, test_data = split_and_encode_data(preprocessed_data)
    print(f"Training set: {len(train_data)} employees (model learns from these)")
    print(f"Test set: {len(test_data)} employees (hidden from model)\n")
    
    # Train survival model
    cph = train_survival_model(train_data)
    
    # Plot analysis results in a single window
    plot_analysis_results(train_data, test_data, cph)
    
    # Print risk summary findings
    generate_executive_report(cph, test_data)


if __name__ == '__main__':
    main()